import React, { useEffect, useMemo, useState } from 'react';
import Calendar from 'react-calendar';
import 'react-calendar/dist/Calendar.css';

import { bookingApi } from '../../api/bookingApi';
import { ROOMS } from '../../utils/constants';
import LoadingSpinner from '../../components/common/LoadingSpinner';
import ErrorAlert from '../../components/common/ErrorAlert';

const toDayStartIso = (date) => {
	const d = new Date(date);
	d.setHours(0, 0, 0, 0);
	return d.toISOString();
};

const toDayEndIso = (date) => {
	const d = new Date(date);
	d.setHours(23, 59, 59, 999);
	return d.toISOString();
};

const toMonthStartIso = (date) => {
	const d = new Date(date.getFullYear(), date.getMonth(), 1);
	d.setHours(0, 0, 0, 0);
	return d.toISOString();
};

const toMonthEndIso = (date) => {
	const d = new Date(date.getFullYear(), date.getMonth() + 1, 0);
	d.setHours(23, 59, 59, 999);
	return d.toISOString();
};

const toDateKey = (date) => {
	const d = new Date(date);
	const yyyy = d.getFullYear();
	const mm = `${d.getMonth() + 1}`.padStart(2, '0');
	const dd = `${d.getDate()}`.padStart(2, '0');
	return `${yyyy}-${mm}-${dd}`;
};

const formatTime = (dateString) =>
	new Date(dateString).toLocaleTimeString(undefined, {
		hour: '2-digit',
		minute: '2-digit',
	});

const BookingCalendar = () => {
	const [selectedRoomId, setSelectedRoomId] = useState(ROOMS?.[0]?.id || '');
	const [selectedDate, setSelectedDate] = useState(new Date());
	const [activeStartDate, setActiveStartDate] = useState(new Date());
	const [loading, setLoading] = useState(false);
	const [monthLoading, setMonthLoading] = useState(false);
	const [error, setError] = useState(null);
	const [dayBookings, setDayBookings] = useState([]);
	const [monthBookings, setMonthBookings] = useState([]);

	const selectedRoom = useMemo(() => {
		const id = typeof selectedRoomId === 'string' ? parseInt(selectedRoomId, 10) : selectedRoomId;
		return ROOMS.find((r) => r.id === id);
	}, [selectedRoomId]);

	useEffect(() => {
		const load = async () => {
			if (!selectedRoomId) return;

			try {
				setLoading(true);
				setError(null);

				const resourceId = parseInt(selectedRoomId, 10);
				const startDate = toDayStartIso(selectedDate);
				const endDate = toDayEndIso(selectedDate);

				const data = await bookingApi.getAllBookings({ resourceId, startDate, endDate });

				const visible = (data || []).filter(
					(b) => b.status !== 'REJECTED' && b.status !== 'CANCELLED'
				);

				visible.sort((a, b) => new Date(a.startTime) - new Date(b.startTime));
				setDayBookings(visible);
			} catch (err) {
				setError(typeof err === 'string' ? err : err?.message || 'Failed to load availability');
				setDayBookings([]);
			} finally {
				setLoading(false);
			}
		};

		load();
	}, [selectedRoomId, selectedDate]);

	useEffect(() => {
		const loadMonth = async () => {
			if (!selectedRoomId) return;

			try {
				setMonthLoading(true);

				const resourceId = parseInt(selectedRoomId, 10);
				const startDate = toMonthStartIso(activeStartDate);
				const endDate = toMonthEndIso(activeStartDate);

				const data = await bookingApi.getAllBookings({ resourceId, startDate, endDate });
				setMonthBookings(data || []);
			} catch {
				setMonthBookings([]);
			} finally {
				setMonthLoading(false);
			}
		};

		loadMonth();
	}, [selectedRoomId, activeStartDate]);

	const dateStatusMap = useMemo(() => {
		const map = new Map();
		(monthBookings || []).forEach((b) => {
			if (!b?.startTime || !b?.status) return;
			if (b.status !== 'PENDING' && b.status !== 'APPROVED' && b.status !== 'REJECTED') return;

			const key = toDateKey(b.startTime);
			const existing = map.get(key) || { PENDING: 0, APPROVED: 0, REJECTED: 0 };
			existing[b.status] = (existing[b.status] || 0) + 1;
			map.set(key, existing);
		});
		return map;
	}, [monthBookings]);

	const tileContent = ({ date, view }) => {
		if (view !== 'month') return null;
		const key = toDateKey(date);
		const statuses = dateStatusMap.get(key);
		if (!statuses) return null;
		const hasApproved = statuses.APPROVED > 0;
		const hasPending = statuses.PENDING > 0;
		const hasRejected = statuses.REJECTED > 0;
		if (!hasApproved && !hasPending && !hasRejected) return null;

		return (
			<div className="calendar-dots" aria-hidden="true">
				{hasApproved ? <span className="calendar-dot dot-approved" /> : null}
				{hasPending ? <span className="calendar-dot dot-pending" /> : null}
				{hasRejected ? <span className="calendar-dot dot-rejected" /> : null}
			</div>
		);
	};

	return (
		<section className="availability-card">
			<div className="availability-header">
				<div>
					<h2>Check Availability</h2>
					<p>Pick a room and a date to see existing bookings.</p>
				</div>

				<div className="availability-controls">
					<label className="availability-label">
						Room
						<select
							value={selectedRoomId}
							onChange={(e) => setSelectedRoomId(e.target.value)}
						>
							{ROOMS.map((room) => (
								<option key={room.id} value={room.id}>
									{room.name}
								</option>
							))}
						</select>
					</label>
				</div>
			</div>

			{error ? <ErrorAlert message={error} /> : null}

			<div className="availability-body">
				<div className="availability-calendar">
					<Calendar
						value={selectedDate}
						onChange={setSelectedDate}
						onActiveStartDateChange={({ activeStartDate: nextStartDate, view }) => {
							if (view === 'month' && nextStartDate) {
								setActiveStartDate(nextStartDate);
							}
						}}
						tileContent={tileContent}
					/>
					{monthLoading ? <div className="calendar-dots-loading" aria-hidden="true" /> : null}
				</div>

				<div className="availability-slots">
					<div className="availability-slots-head">
						<h3>{selectedRoom?.name || 'Selected room'}</h3>
						<small>
							{selectedDate.toLocaleDateString(undefined, {
								weekday: 'short',
								year: 'numeric',
								month: 'short',
								day: '2-digit',
							})}
						</small>
					</div>

					{loading ? (
						<LoadingSpinner />
					) : dayBookings.length === 0 ? (
						<p className="no-data">No bookings for this date.</p>
					) : (
						<ul className="availability-list">
							{dayBookings.map((b) => (
								<li key={b.id} className="availability-item">
									<div className="availability-time">
										{formatTime(b.startTime)} - {formatTime(b.endTime)}
									</div>
									<div className="availability-meta">
										<strong>BK-{b.id}</strong>
										<span>{b.userName || 'Campus User'}</span>
									</div>
									<div className="availability-status">{b.status}</div>
								</li>
							))}
						</ul>
					)}
				</div>
			</div>
		</section>
	);
};

export default BookingCalendar;
